input = ["",
"",
"","
",
""].map! {|line| line.split('')}

tests = {
  1 => "ULL".split(''),
  9 => "RRDDD".split(''),
  8 => "LURDL".split(''),
  5 => "UUUUD".split('')
}


def run (instructions, key)
  return key if instructions == []
  i = instructions[0]
  if i == "U" and key > 3
    key -= 3
  elsif i == "L" and ![1,4,7].include? key
    key -= 1
  elsif i == "R" and ![3,6,9].include? key
    key += 1
  elsif i == "D" and key < 7
    key += 3
  end
  return run(instructions[1..instructions.length], key)
end

if ARGV[0] == 'test'
    puts 1 == run("ULL".split(''), 5) ? "PASSED" : "FAILED (expected: 1, result: #{run("ULL".split(''), 5)})"
    puts 9 == run("RRDDD".split(''), 1) ? "PASSED" : "FAILED (expected: 9, result: #{run("RRDDD".split(''), 1)})"
    puts 8 == run("LURDL".split(''), 9) ? "PASSED" : "FAILED (expected: 8, result: #{run("LURDL".split(''), 9)})"
    puts 5 == run("UUUUD".split(''), 8) ? "PASSED" : "FAILED (expected: 5, result: #{run("UUUUD".split(''), 8)})"
end

print run(input[0], 5)
print run(input[1], 9)
print run(input[2], 8)
print run(input[3], 5)
print run(input[4], 7)
